style:
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
      background: #f0f2f5;
      display: flex;
      min-height: 100vh;
    }

    /* ── Sidebar ── */
    .sidebar {
      width: 260px;
      background: #fff;
      border-right: 1px solid #e0e0e0;
      display: flex;
      flex-direction: column;
      height: 100vh;
      position: sticky;
      top: 0;
      flex-shrink: 0;
    }

    .sb-head {
      padding: 18px 16px 14px;
      border-bottom: 1px solid #f0f0f0;
    }

    .brand-row {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-bottom: 10px;
    }

    .brand-logo {
      width: 38px;
      height: 38px;
      border-radius: 10px;
      background: linear-gradient(135deg, var(--accent), var(--brand));
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 16px;
      font-weight: 900;
      color: #fff;
      flex-shrink: 0;
    }

    .brand-name {
      font-size: 15px;
      font-weight: 700;
      color: #111;
      line-height: 1.2;
    }

    .brand-industry {
      font-size: 11px;
      color: #888;
    }

    .journey-lbl {
      font-size: 11px;
      font-weight: 700;
      color: var(--brand);
      text-transform: uppercase;
      letter-spacing: .5px;
    }

    .step-list {
      flex: 1;
      overflow-y: auto;
      padding: 8px 0;
    }

    .step-item {
      display: flex;
      align-items: flex-start;
      gap: 9px;
      padding: 9px 14px;
      cursor: pointer;
      border-left: 3px solid transparent;
      transition: all .15s;
    }

    .step-item:hover {
      background: #fff5f5;
    }

    .step-item.active {
      background: #fff0f0;
      border-left-color: var(--brand);
    }

    .step-num {
      width: 20px;
      height: 20px;
      border-radius: 50%;
      background: #e8e8e8;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 10px;
      font-weight: 700;
      color: #666;
      flex-shrink: 0;
      margin-top: 2px;
    }

    .step-item.active .step-num {
      background: var(--brand);
      color: #fff;
    }

    .step-lbl {
      font-size: 12px;
      font-weight: 600;
      color: #333;
      line-height: 1.35;
    }

    .step-item.active .step-lbl {
      color: var(--brand);
    }

    .step-meta {
      font-size: 10px;
      color: #aaa;
      margin-top: 1px;
    }

    .sb-foot {
      padding: 10px 14px;
      border-top: 1px solid #f0f0f0;
      font-size: 10px;
      color: #aaa;
      text-align: center;
    }

    /* ── Main ── */
    .main {
      flex: 1;
      display: flex;
      flex-direction: column;
      min-height: 100vh;
      overflow: hidden;
    }

    .main-head {
      background: #fff;
      border-bottom: 1px solid #e8e8e8;
      padding: 13px 28px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      flex-shrink: 0;
    }

    .step-title {
      font-size: 16px;
      font-weight: 700;
      color: #111;
    }

    .step-counter {
      font-size: 12px;
      color: #888;
      background: #f5f5f5;
      border-radius: 20px;
      padding: 4px 12px;
    }

    .step-desc-bar {
      background: #fff;
      border-bottom: 1px solid #f0f0f0;
      padding: 7px 28px;
      display: flex;
      align-items: center;
      gap: 8px;
      font-size: 12px;
      color: #555;
      flex-shrink: 0;
      flex-wrap: wrap;
    }

    .tag {
      display: inline-flex;
      align-items: center;
      padding: 2px 8px;
      border-radius: 10px;
      font-size: 10px;
      font-weight: 700;
      white-space: nowrap;
    }

    .tag-mktg {
      background: #fce4ec;
      color: #C62828;
    }

    .tag-web {
      background: #f3e5f5;
      color: #6A1B9A;
    }

    .tag-session {
      background: #e3f2fd;
      color: #1565C0;
    }

    .tag-util {
      background: #e8f5e9;
      color: #2E7D32;
    }

    .tag-act {
      background: #fff3e0;
      color: #E65100;
    }

    .tag-ord {
      background: #e8f5e9;
      color: #1B5E20;
    }

    .tag-ai {
      background: #ede7f6;
      color: #4527A0;
    }

    .tag-pay {
      background: #e0f2f1;
      color: #00695C;
    }

    .tag-inv {
      background: #fff8e1;
      color: #F57F17;
    }

    .tag-cmp {
      background: #fce4ec;
      color: #880E4F;
    }

    .tag-dist {
      background: #e8eaf6;
      color: #283593;
    }

    .tag-sch {
      background: #f9fbe7;
      color: #558B2F;
    }

    .screens-area {
      flex: 1;
      overflow-y: auto;
      overflow-x: auto;
      padding: 24px 16px;
      background: #f0f2f5;
    }

    .step-section {
      display: none;
      width: 100%;
      justify-content: center;
      gap: 20px;
      flex-wrap: wrap;
      align-items: flex-start;
    }

    .step-section.active {
      display: flex;
      flex-wrap: nowrap;
    }
    #step-6.active {
      display: flex;
      flex-wrap: nowrap;
      align-items: flex-start;
      justify-content: flex-start;
      gap: 16px;
      overflow-x: auto;
    }
    #step-6 .screen-wrap {
      flex-shrink: 0;
    }

    #step-2.active {
      flex-wrap: nowrap;
      align-items: flex-start;
      gap: 24px;
      overflow: visible;
    }

    #step-3.active {
      flex-wrap: nowrap;
      align-items: flex-start;
      justify-content: flex-start;
      gap: 16px;
      overflow-x: auto;
    }

    #step-4.active {
      flex-wrap: nowrap;
      align-items: flex-start;
      justify-content: center;
      gap: 16px;
      overflow-x: auto;
    }

    .step2-phones {
      display: flex;
      gap: 20px;
      flex-wrap: wrap;
      justify-content: center;
      flex-shrink: 0;
    }

    .screen-wrap {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 8px;
    }

    .screen-lbl {
      font-size: 10.5px;
      color: #888;
      text-transform: uppercase;
      letter-spacing: .5px;
      font-weight: 600;
    }

    .screen-type-lbl {
      font-size: 10px;
      color: #aaa;
      margin-top: 1px;
    }

    /* ─── Screen description card ─── */
    .screen-desc {
      width: 375px;
      border-radius: 12px;
      padding: 10px 14px 11px;
      font-size: 13px;
      line-height: 1.5;
      color: #2a2a2a;
    }

    .screen-desc strong {
      font-size: 13.5px;
      font-weight: 700;
      color: #111;
      display: block;
      margin-bottom: 3px;
    }


    /* ── Nav bar ── */
    .nav-bar {
      background: #fff;
      border-top: 1px solid #e8e8e8;
      padding: 12px 28px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      flex-shrink: 0;
    }

    .nav-btn {
      padding: 8px 18px;
      border-radius: 8px;
      border: 1.5px solid #e0e0e0;
      background: #fff;
      font-size: 13px;
      font-weight: 600;
      color: #333;
      cursor: pointer;
      transition: all .15s;
      display: flex;
      align-items: center;
      gap: 6px;
    }

    .nav-btn:hover:not(:disabled) {
      border-color: var(--brand);
      color: var(--brand);
      background: #fff0f0;
    }

    .nav-btn:disabled {
      opacity: .3;
      cursor: not-allowed;
    }

    .nav-btn.primary {
      background: var(--brand);
      border-color: var(--brand);
      color: #fff;
    }

    .nav-btn.primary:hover:not(:disabled) {
      background: var(--brand-dark);
      border-color: var(--brand-dark);
    }

    /* ── DM Phone frame ── */
    .phone-frame {
      width: 305px;
      border-radius: 38px;
      border: 8px solid #1a1a1a;
      box-shadow: 0 20px 60px rgba(0, 0, 0, .3);
      overflow: hidden;
      display: flex;
      flex-direction: column;
      background: #ECE5DD;
      height: 610px;
      position: relative;
      flex-shrink: 0;
    }

    .status-bar {
      background: #075E54;
      padding: 8px 14px 5px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      flex-shrink: 0;
    }

    .status-time {
      font-size: 13px;
      font-weight: 600;
      color: #fff;
    }

    .status-icons {
      display: flex;
      align-items: center;
      gap: 5px;
    }

    .wa-topbar {
      background: #075E54;
      padding: 6px 10px 8px;
      display: flex;
      align-items: center;
      gap: 8px;
      flex-shrink: 0;
      border-bottom: 1px solid rgba(0, 0, 0, .1);
    }

    .wa-back {
      display: flex;
      align-items: center;
      padding-right: 2px;
    }

    .wa-avatar {
      width: 36px;
      height: 36px;
      border-radius: 50%;
      background: linear-gradient(135deg, var(--accent), var(--brand));
      flex-shrink: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 13px;
      font-weight: 900;
      color: #fff;
    }

    .wa-contact {
      flex: 1;
    }

    .wa-contact-name {
      font-size: 14px;
      font-weight: 600;
      color: #fff;
      line-height: 1.2;
    }

    .wa-contact-status {
      font-size: 11px;
      color: rgba(255, 255, 255, .75);
    }

    .wa-actions {
      display: flex;
      align-items: center;
      gap: 14px;
    }

    .chat-area {
      flex: 1;
      overflow-y: auto;
      background-color: #ECE5DD;
      background-image: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23b2a99a' fill-opacity='0.13'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");
      padding: 8px 7px;
      display: flex;
      flex-direction: column;
      gap: 3px;
    }

    .input-bar {
      background: #f0f0f0;
      padding: 6px 8px;
      display: flex;
      align-items: center;
      gap: 8px;
      flex-shrink: 0;
    }

    .input-field {
      flex: 1;
      background: #fff;
      border-radius: 22px;
      padding: 7px 14px;
      font-size: 13px;
      color: #8696a0;
    }

    /* ── Bubbles ── */
    .msg-sender-wrap {
      display: flex;
      flex-direction: column;
      align-items: flex-end;
      margin-bottom: 2px;
    }

    .msg-receiver-wrap {
      display: flex;
      flex-direction: column;
      align-items: flex-start;
      margin-bottom: 2px;
    }

    .msg-sender {
      background: #DCF8C6;
      border-radius: 8px 8px 0 8px;
      padding: 6px 9px 4px;
      max-width: 225px;
      box-shadow: 0 1px 2px rgba(0, 0, 0, .1);
    }

    .msg-receiver {
      background: #fff;
      border-radius: 0 8px 8px 8px;
      padding: 6px 9px 4px;
      max-width: 225px;
      box-shadow: 0 1px 2px rgba(0, 0, 0, .1);
    }

    .msg-body {
      font-size: 13px;
      color: #111B21;
      line-height: 1.45;
    }

    .msg-time {
      font-size: 10px;
      color: #667781;
      text-align: right;
      display: block;
      margin-top: 2px;
    }

    .msg-tick {
      color: #53bdeb;
    }

    .date-pill {
      background: rgba(255, 255, 255, .8);
      border-radius: 8px;
      padding: 2px 10px;
      font-size: 10.5px;
      color: #667781;
      align-self: center;
      margin: 4px 0 6px;
    }

    /* ── Template card ── */
    .wa-tmpl {
      background: #fff;
      border-radius: 8px 0 8px 8px;
      max-width: 252px;
      overflow: hidden;
      box-shadow: 0 1px 3px rgba(0, 0, 0, .13);
    }

    .wa-hdr-img {
      width: 100%;
      height: 140px;
      overflow: hidden;
      position: relative;
      flex-shrink: 0;
    }

    .wa-hdr-img img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      display: block;
    }

    .wa-hdr-txt {
      background: #f5f5f5;
      padding: 8px 11px 7px;
      font-size: 13.5px;
      font-weight: 700;
      color: #111B21;
      border-bottom: 1px solid #eee;
    }

    .wa-tmpl-body {
      padding: 8px 11px 4px;
      font-size: 12.5px;
      color: #111B21;
      line-height: 1.5;
    }

    .wa-tmpl-footer {
      font-size: 10.5px;
      color: #667781;
      padding: 2px 11px 4px;
    }

    .wa-tmpl-signoff {
      font-size: 13.5px;
      color: #111B21;
      padding: 6px 12px 0;
      line-height: 1.5;
    }

    .wa-tmpl-time {
      font-size: 10px;
      color: #667781;
      text-align: right;
      padding: 2px 10px 6px;
    }

    .wa-tmpl-btns {
      border-top: 1px solid #f0f0f0;
    }

    .wa-qr-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      width: 100%;
      padding: 10px;
      font-size: 13px;
      font-weight: 500;
      color: #00A884;
      background: none;
      border: none;
      border-bottom: 1px solid #f0f0f0;
      cursor: pointer;
    }

    .wa-qr-btn:last-child {
      border-bottom: none;
    }

    .wa-cta-btn {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      width: 100%;
      padding: 10px;
      font-size: 13px;
      font-weight: 500;
      color: #00A884;
      background: none;
      border: none;
      border-bottom: 1px solid #f0f0f0;
      cursor: pointer;
    }

    .wa-cta-btn:last-child {
      border-bottom: none;
    }

    .zotok-footer {
      font-size: 9.5px;
      color: #8696a0;
      text-align: center;
      padding: 3px 0 0;
    }

    /* ── Interactive list card ── */
    .wa-list-card {
      background: #fff;
      border-radius: 0 8px 8px 8px;
      max-width: 252px;
      overflow: hidden;
      box-shadow: 0 1px 3px rgba(0, 0, 0, .13);
    }

    .wa-list-body {
      padding: 8px 11px 4px;
      font-size: 12.5px;
      color: #111B21;
      line-height: 1.5;
    }

    .wa-list-time {
      font-size: 10px;
      color: #667781;
      text-align: right;
      padding: 2px 10px 5px;
    }

    .wa-list-btn-row {
      border-top: 1px solid #f0f0f0;
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      padding: 10px 12px;
      cursor: pointer;
    }

    .wa-list-btn-label {
      font-size: 14px;
      font-weight: 600;
      color: #00A884;
    }

    /* ── Bottom sheet modal ── */
    .modal-overlay {
      position: absolute;
      top: 0;
      left: 0;
      right: 0;
      bottom: 0;
      background: rgba(0, 0, 0, .45);
      z-index: 20;
      display: flex;
      flex-direction: column;
      justify-content: flex-end;
    }

    .modal-sheet {
      background: #fff;
      border-radius: 16px 16px 0 0;
      overflow: hidden;
      display: flex;
      flex-direction: column;
      max-height: 510px;
    }

    .modal-handle-row {
      display: flex;
      justify-content: center;
      padding: 10px 0 4px;
      background: #fff;
      flex-shrink: 0;
    }

    .modal-handle-bar {
      width: 36px;
      height: 4px;
      background: #ddd;
      border-radius: 2px;
    }

    .modal-topbar-row {
      display: flex;
      align-items: center;
      padding: 4px 14px 10px;
      background: #fff;
      border-bottom: 1px solid #f0f0f0;
      flex-shrink: 0;
    }

    .modal-close {
      font-size: 17px;
      color: #666;
      width: 26px;
      height: 26px;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
    }

    .modal-title {
      flex: 1;
      text-align: center;
      font-size: 16px;
      font-weight: 700;
      color: #111B21;
    }

    .modal-spacer {
      width: 26px;
      flex-shrink: 0;
    }

    .modal-section-lbl {
      font-size: 11.5px;
      color: #667781;
      padding: 8px 16px 5px;
      background: #f8f8f8;
      border-top: 1px solid #f0f0f0;
      border-bottom: 1px solid #f0f0f0;
      font-weight: 600;
      text-transform: uppercase;
      letter-spacing: .4px;
      flex-shrink: 0;
    }

    .modal-rows {
      overflow-y: auto;
      flex: 1;
    }

    .modal-row {
      padding: 10px 16px;
      border-bottom: 1px solid #f2f2f2;
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      gap: 8px;
      cursor: pointer;
    }

    .modal-row:last-child {
      border-bottom: none;
    }

    .modal-row-content {
      flex: 1;
    }

    .modal-row-title {
      font-size: 13.5px;
      font-weight: 600;
      color: #111B21;
    }

    .modal-row-desc {
      font-size: 11.5px;
      color: #667781;
      margin-top: 1px;
      line-height: 1.35;
    }

    .modal-row-radio {
      width: 18px;
      height: 18px;
      border-radius: 50%;
      border: 2px solid #ccc;
      flex-shrink: 0;
      margin-top: 2px;
    }

    .modal-send-wrap {
      padding: 10px 16px 6px;
      background: #fff;
      flex-shrink: 0;
      border-top: 1px solid #f0f0f0;
    }

