    /* ── Menu explainer panel ── */
    .menu-explainer {
      width: 374px;
      background: #fff;
      border-radius: 16px;
      padding: 22px 22px 16px;
      box-shadow: 0 4px 20px rgba(0, 0, 0, .1);
      align-self: flex-start;
      flex-shrink: 0;
    }

    .menu-explainer-hdr {
      margin-bottom: 16px;
      padding-bottom: 10px;
      border-bottom: 2px solid var(--brand);
    }

    .menu-explainer-hdr-title {
      font-size: 14px;
      font-weight: 800;
      color: var(--brand);
      text-transform: uppercase;
      letter-spacing: .6px;
    }

    .menu-explainer-hdr-sub {
      font-size: 11px;
      color: #999;
      margin-top: 2px;
    }

    .menu-section {
      margin-bottom: 12px;
    }

    .menu-section-lbl {
      font-size: 10.5px;
      font-weight: 700;
      color: var(--brand);
      text-transform: uppercase;
      letter-spacing: .4px;
      margin-bottom: 6px;
    }

    .menu-item-card {
      width: 100%;
      background: #fff8f8;
      border-radius: 10px;
      padding: 8px 12px 9px;
      border-left: 3px solid var(--accent);
