    }

    .menu-item-name {
      font-size: 12.5px;
      font-weight: 700;
      color: #111;
      margin-bottom: 2px;
    }

    .menu-item-desc {
      font-size: 11px;
      color: #555;
      line-height: 1.45;
    }


    /* ── Typing indicator ── */
    .msg-typing {
      background: #fff;
      border-radius: 0 8px 8px 8px;
      padding: 10px 14px;
      display: flex;
      gap: 5px;
      align-items: center;
      box-shadow: 0 1px 2px rgba(0, 0, 0, .1);
    }

    .t-dot {
      width: 7px;
      height: 7px;
      border-radius: 50%;
      background: #aaa;
      animation: tdot 1.4s infinite;
    }

    .t-dot:nth-child(2) {
      animation-delay: .2s;
    }

    .t-dot:nth-child(3) {
      animation-delay: .4s;
    }

    @keyframes tdot {

      0%,
      60%,
      100% {
        opacity: .3;
      }

      30% {
        opacity: 1;
      }
    }

    /* ── SVG icons ── */
    svg {
      display: inline-block;
      vertical-align: middle;
    }

    /* ════════════════════════════════════════
   DESKTOP — hide mobile chrome
   ════════════════════════════════════════ */
    @media (min-width:769px) {
      .mob-swipe-hint {
        display: none !important;
      }

      .mob-hamburger {
        display: none !important;
      }

      .mob-sb-close {
        display: none !important;
      }

      .mob-overlay {
        display: none !important;
      }
    }

    /* ════════════════════════════════════════
   MOBILE LAYOUT OVERRIDES (≤768px)
   ════════════════════════════════════════ */
    @media (max-width:768px) {

      .sidebar {
        position: fixed;
        left: 0;
        top: 0;
        bottom: 0;
        z-index: 1000;
        transform: translateX(-100%);
        transition: transform .26s cubic-bezier(.4, 0, .2, 1);
        box-shadow: 4px 0 28px rgba(0, 0, 0, .22);
        height: 100%;
        overflow-y: auto;
      }

      .sidebar.mob-open {
        transform: translateX(0);
      }

      .mob-overlay {
        display: none;
        position: fixed;
        inset: 0;
        background: rgba(0, 0, 0, .42);
        z-index: 999;
        -webkit-tap-highlight-color: transparent;
      }

      .mob-overlay.mob-open {
        display: block;
      }

      .mob-sb-close {
        position: absolute;
        top: 10px;
        right: 10px;
        width: 28px;
        height: 28px;
        border: none;
        background: none;
        font-size: 20px;
        line-height: 1;
        cursor: pointer;
        color: #888;
        display: flex;
        align-items: center;
        justify-content: center;
      }

      .mob-hamburger {
        display: flex;
        flex-direction: column;
        justify-content: center;
        gap: 5px;
        cursor: pointer;
        padding: 5px;
        flex-shrink: 0;
        -webkit-tap-highlight-color: transparent;
      }

      .mob-hamburger span {
        display: block;
        width: 22px;
        height: 2.5px;
        background: #555;
        border-radius: 2px;
      }

      .main {
        overflow: hidden;
      }

      .main-head {
        padding: 8px 14px;
        gap: 10px;
      }

      .step-title {
        font-size: 13px;
        flex: 1;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
      }

      .step-desc-bar {
        display: none !important;
      }

      .step-counter {
        display: none !important;
      }

      .screen-lbl {
        display: none !important;
      }

      .screens-area {
        display: flex !important;
        flex-direction: row;
        overflow-x: auto;
        overflow-y: hidden;
        scroll-snap-type: x mandatory;
        -webkit-overflow-scrolling: touch;
        scrollbar-width: none;
        padding: 0;
        gap: 0;
        background: #f0f2f5;
        flex: 1;
      }

      .screens-area::-webkit-scrollbar {
        display: none;
      }

      .step-section {
        display: contents !important;
      }

      .screen-wrap {
        width: 100vw !important;
        min-width: 100vw !important;
        flex-shrink: 0;
        scroll-snap-align: start;
        display: flex !important;
        flex-direction: column;
        align-items: center;
        justify-content: flex-start;
        padding: 14px 12px 80px;
        overflow-y: auto;
        overflow-x: hidden;
        gap: 10px;
        box-sizing: border-box;
      }

      .screen-lbl {
        font-size: 11px;
        color: #888;
        text-transform: uppercase;
        letter-spacing: .5px;
        font-weight: 600;
        align-self: flex-start;
        padding-left: 4px;
      }

      .menu-explainer {
        display: none !important;
      }

      .step2-phones {
        display: contents !important;
      }

      .nav-bar {
        display: none !important;
      }

      .mob-swipe-hint {
        position: fixed;
        bottom: 0;
        left: 0;
        right: 0;
        background: rgba(255, 255, 255, .95);
        border-top: 1px solid #e8e8e8;
        padding: 7px 16px;
        display: flex;
        align-items: center;
        justify-content: space-between;
        z-index: 100;
        font-size: 12px;
        color: #888;
      }

      .mob-swipe-dots {
        display: flex;
        gap: 5px;
        align-items: center;
      }

      .mob-dot {
        width: 6px;
        height: 6px;
        border-radius: 50%;
        background: #ddd;
        transition: background .2s, width .2s;
      }

      .mob-dot.active {
        background: var(--brand);
        width: 16px;
        border-radius: 3px;
      }

      .mob-prev-btn,
      .mob-next-btn {
        background: var(--brand);
        color: #fff;
        border: none;
        border-radius: 8px;
        padding: 6px 14px;
        font-size: 12px;
        font-weight: 600;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
      }

      .mob-prev-btn:disabled,
      .mob-next-btn:disabled {
        background: #ccc;
        cursor: not-allowed;
      }

      .chat-area {
        overscroll-behavior: contain;
      }

      .screens-area {
        overscroll-behavior-y: none;
      }

      /* Screen desc — fixed overlay above nav bar, fades in */
      .screen-desc {
        position: fixed !important;
        left: 16px !important;
        right: 16px !important;
        bottom: 58px !important;
        width: auto !important;
        max-width: none !important;
        z-index: 200;
        opacity: 0;
        pointer-events: none;
        transition: opacity 0.5s ease;
        backdrop-filter: blur(4px);
        -webkit-backdrop-filter: blur(4px);
        border-radius: 14px !important;
        box-shadow: 0 8px 28px rgba(0, 0, 0, 0.18) !important;
        font-size: 13px !important;
      }

      .screen-desc.desc-visible {
        opacity: 0.93;
        pointer-events: auto;
      }

      .screen-desc strong {
        font-size: 13.5px !important;
      }

    }

    /* end @media (max-width:768px) */

